namespace MCMF {
  const int MAXN = 10000 + 10;
  const int INF = 0x3f3f3f3f;

  struct Edge {
    int from, to, cap, flow, cost;
    Edge(int from = 0, int to = 0, int cap = 0, int flow = 0, int cost = 0)
        : from(from), to(to), cap(cap), flow(flow), cost(cost) {
    }
  };

  int s, t;
  int cost, flow;
  int path[MAXN];
  int dist[MAXN];
  std::vector<Edge> edges;
  std::vector<int> G[MAXN];

  void init(int source = 0, int converge = 1, int N = MAXN) {
    s = source;
    t = converge;
    cost = 0;
    flow = 0;
    edges.clear();
    for (int i = 0; i < N; ++i) G[i].clear();
  }

  void addedge(int from, int to, int cap, int cost) {
    int siz = edges.size();
    edges.push_back(Edge(from, to, cap, 0, cost));
    edges.push_back(Edge(to, from, 0, 0, -cost));
    G[from].push_back(siz);
    G[to].push_back(siz + 1);
  }

  bool spfa() {
    static std::queue<int> Q;
    static bool inq[MAXN];

    memset(dist, 0x3f, sizeof dist);
    Q.push(s);
    inq[s] = true;
    dist[s] = 0;

    while (!Q.empty()) {
      int o = Q.front();
      Q.pop();
      for (int i = 0; i < G[o].size(); ++i) {
        Edge& e = edges[G[o][i]];
        if (e.cap > e.flow && dist[e.to] > dist[o] + e.cost) {
          dist[e.to] = dist[o] + e.cost;
          path[e.to] = G[o][i];
          if (inq[e.to]) continue;
          inq[e.to] = true;
          Q.push(e.to);
        }
      }
      inq[o] = false;
    }

    return dist[t] != INF;
  }

  std::pair<int, int> mincostmaxflow() {
    while (spfa()) {
      int mif = INF;
      for (int o = t; o != s;) {
        Edge& e = edges[path[o]];
        mif = std::min(mif, e.cap - e.flow);
        o = e.from;
      }
      for (int o = t; o != s;) {
        edges[path[o]].flow += mif;
        edges[path[o] ^ 1].flow -= mif;
        o = edges[path[o]].from;
      }
      flow += mif;
      cost += mif * dist[t];
    }
    return std::make_pair(flow, cost);
  }

  void dfs();

  void solve();
};   // namespace MCMF

